import { useEffect, useState } from "react";
import {
  getPatients,
  addPatient,
  getAppointments,
  addAppointment
} from "../api";

import Sidebar from "./Sidebar";
import Search from "./Search";
import Prescription from "./Prescription";

import jsPDF from "jspdf";
import html2canvas from "html2canvas";

export default function Dashboard() {
  const [page, setPage] = useState("dashboard");

  const [patients, setPatients] = useState([]);
  const [appointments, setAppointments] = useState([]);

  const [patientForm, setPatientForm] = useState({
    name: "",
    phone: "",
    age: ""
  });

  const [appointmentForm, setAppointmentForm] = useState({
    patient_id: "",
    date: ""
  });

  const [searchPatientId, setSearchPatientId] = useState("");

  const doctorId = localStorage.getItem("userId");

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    const patientsData = await getPatients();
    const appointmentsData = await getAppointments();

    setPatients(patientsData || []);
    setAppointments(appointmentsData || []);
  };

  // ================= PATIENT =================
  const handleAddPatient = async () => {
    await addPatient({
      name: patientForm.name,
      phone: patientForm.phone,
      age: Number(patientForm.age)
    });

    setPatientForm({ name: "", phone: "", age: "" });
    loadData();
  };

  // ================= APPOINTMENT =================
  const handleAddAppointment = async () => {
    await addAppointment({
      patient_id: Number(appointmentForm.patient_id),
      doctor_id: Number(doctorId),
      date: new Date(appointmentForm.date).toISOString()
    });

    setAppointmentForm({ patient_id: "", date: "" });
    loadData();
  };

  // ================= FILTER =================
  const filteredAppointments = searchPatientId
    ? appointments.filter(a => a.patient_id === Number(searchPatientId))
    : appointments;

  // ================= PRINT =================
  const handlePrint = () => window.print();

  // ================= PDF =================
  const handleDownloadPDF = async (id) => {
    const element = document.getElementById(id);
    const canvas = await html2canvas(element);
    const imgData = canvas.toDataURL("image/png");

    const pdf = new jsPDF("p", "mm", "a4");
    pdf.addImage(imgData, "PNG", 10, 10, 190, 0);
    pdf.save("report.pdf");
  };

  return (
<div style={{ display: "flex", minHeight: "100vh", background: "#f3f4f6" }}>
      {/* SIDEBAR */}
      <Sidebar setPage={setPage} />

      {/* MAIN CONTENT */}
      <div className="flex-1 p-6">

        {/* ================= DASHBOARD ================= */}
        {page === "dashboard" && (
          <div>
            <h1 className="text-3xl font-bold mb-6">Dashboard Overview</h1>

            <div className="grid grid-cols-2 md:grid-cols-3 gap-6">

              <div className="bg-white p-6 rounded-2xl shadow">
                <h3 className="text-gray-500">Total Patients</h3>
                <p className="text-3xl font-bold">{patients.length}</p>
              </div>

              <div className="bg-white p-6 rounded-2xl shadow">
                <h3 className="text-gray-500">Appointments</h3>
                <p className="text-3xl font-bold">{appointments.length}</p>
              </div>

            </div>
          </div>
        )}

        {/* ================= PATIENTS ================= */}
        {page === "patients" && (
          <div>
            <h1 className="text-2xl font-bold mb-4">Patients</h1>

            <div className="grid grid-cols-3 gap-3 mb-4">
              <input
                className="border p-2 rounded"
                placeholder="Name"
                value={patientForm.name}
                onChange={(e) =>
                  setPatientForm({ ...patientForm, name: e.target.value })
                }
              />

              <input
                className="border p-2 rounded"
                placeholder="Phone"
                value={patientForm.phone}
                onChange={(e) =>
                  setPatientForm({ ...patientForm, phone: e.target.value })
                }
              />

              <input
                className="border p-2 rounded"
                placeholder="Age"
                value={patientForm.age}
                onChange={(e) =>
                  setPatientForm({ ...patientForm, age: e.target.value })
                }
              />
            </div>

            <button
              onClick={handleAddPatient}
              className="bg-blue-600 text-white px-4 py-2 rounded mb-4"
            >
              Add Patient
            </button>

            <div className="flex gap-3 mb-4">
              <button onClick={handlePrint} className="bg-gray-800 text-white px-4 py-2 rounded">
                Print
              </button>

              <button
                onClick={() => handleDownloadPDF("patients-section")}
                className="bg-green-600 text-white px-4 py-2 rounded"
              >
                Download PDF
              </button>
            </div>

            <div id="patients-section" className="space-y-2">
              {patients.map((p) => (
                <div key={p.id} className="bg-white p-3 rounded shadow">
                  ID: {p.id} | {p.name} | {p.phone} | Age: {p.age}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ================= APPOINTMENTS ================= */}
        {page === "appointments" && (
          <div>
            <h1 className="text-2xl font-bold mb-4">Appointments</h1>

            <div className="flex gap-3 mb-3">
              <select
                className="border p-2 rounded"
                value={appointmentForm.patient_id}
                onChange={(e) =>
                  setAppointmentForm({
                    ...appointmentForm,
                    patient_id: e.target.value
                  })
                }
              >
                <option value="">Select Patient</option>
                {patients.map((p) => (
                  <option key={p.id} value={p.id}>
                    {p.name}
                  </option>
                ))}
              </select>

              <input
                type="datetime-local"
                className="border p-2 rounded"
                value={appointmentForm.date}
                onChange={(e) =>
                  setAppointmentForm({
                    ...appointmentForm,
                    date: e.target.value
                  })
                }
              />

              <button
                onClick={handleAddAppointment}
                className="bg-blue-600 text-white px-4 py-2 rounded"
              >
                Add
              </button>
            </div>

            <input
              className="border p-2 rounded mb-3"
              placeholder="Filter by Patient ID"
              value={searchPatientId}
              onChange={(e) => setSearchPatientId(e.target.value)}
            />

            <div className="flex gap-3 mb-4">
              <button onClick={handlePrint} className="bg-gray-800 text-white px-4 py-2 rounded">
                Print
              </button>

              <button
                onClick={() => handleDownloadPDF("appointments-section")}
                className="bg-green-600 text-white px-4 py-2 rounded"
              >
                Download PDF
              </button>
            </div>

            <div id="appointments-section" className="space-y-2">
              {filteredAppointments.map((a) => (
                <div key={a.id} className="bg-white p-3 rounded shadow">
                  Patient ID: {a.patient_id} |{" "}
                  {new Date(a.date).toLocaleString()}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ================= SEARCH ================= */}
        {page === "search" && <Search />}

        {/* ================= PRESCRIPTION ================= */}
        {page === "prescription" && <Prescription />}

      </div>
    </div>
  );
}
